solution: ```class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int totalOnes = 0;
        for (int num : nums) totalOnes += num;

        int maxScore = 0;
        List<Integer> res = new ArrayList<>();
        int zerosLeft = 0;
        int onesRight = totalOnes;

        for (int i = 0; i <= n; i++) {
            int score = zerosLeft + onesRight;
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.add(i);
            } else if (score == maxScore) {
                res.add(i);
            }
            if (i < n) {
                if (nums[i] == 0) zerosLeft++;
                else onesRight--;
            }
        }
        return res;
    }
}
